// ================================================
//  EDIT THIS NODE -- all your settings live here
// ================================================

const BUSINESS_NAME    = 'Your Business Name';
const REPORT_EMAIL     = 'user@example.com';
const METRICS_DESCRIPTION = 'Revenue (USD), New Leads, Sales Calls Booked, Deals Closed, Refunds';

// ================================================
//  DO NOT EDIT BELOW THIS LINE
// ================================================

const now   = new Date();
const today = now.toISOString().split('T')[0];

// This week: last 7 days
const thisWeekEnd   = new Date(now);
const thisWeekStart = new Date(now);
thisWeekStart.setDate(thisWeekStart.getDate() - 7);

// Last week: 8-14 days ago
const lastWeekEnd   = new Date(thisWeekStart);
const lastWeekStart = new Date(thisWeekStart);
lastWeekStart.setDate(lastWeekStart.getDate() - 7);

function fmt(d) { return d.toISOString().split('T')[0]; }

return [{
  json: {
    business_name:        BUSINESS_NAME,
    report_email:         REPORT_EMAIL,
    metrics_description:  METRICS_DESCRIPTION,
    run_date:             today,
    this_week_start:      fmt(thisWeekStart),
    this_week_end:        fmt(thisWeekEnd),
    last_week_start:      fmt(lastWeekStart),
    last_week_end:        fmt(lastWeekEnd)
  }
}];

const cfg     = $('Configure Report Settings').first().json;
const allItems = $input.all();

// Split into this week vs last week based on item order
// Fetch This Week feeds first batch, Fetch Last Week feeds second
// We'll use all items and label them by date column
const rows = allItems.map(function(item) { return item.json; });

// Build a readable text block for Claude
const thisWeekRows = rows.filter(function(r) {
  return r.Date >= cfg.this_week_start && r.Date <= cfg.this_week_end;
});

const lastWeekRows = rows.filter(function(r) {
  return r.Date >= cfg.last_week_start && r.Date <= cfg.last_week_end;
});

function rowsToText(rowArr) {
  if (!rowArr || rowArr.length === 0) return 'No data found for this period.';
  const headers = Object.keys(rowArr[0]).join(' | ');
  const lines   = rowArr.map(function(r) { return Object.values(r).join(' | '); });
  return headers + '\n' + lines.join('\n');
}

const formattedData = 'THIS WEEK (' + cfg.this_week_start + ' to ' + cfg.this_week_end + '):\n'
  + rowsToText(thisWeekRows)
  + '\n\nLAST WEEK (' + cfg.last_week_start + ' to ' + cfg.last_week_end + '):\n'
  + rowsToText(lastWeekRows);

return [{
  json: {
    business_name:       cfg.business_name,
    report_email:        cfg.report_email,
    metrics_description: cfg.metrics_description,
    run_date:            cfg.run_date,
    this_week_start:     cfg.this_week_start,
    this_week_end:       cfg.this_week_end,
    formatted_data:      formattedData,
    this_week_row_count: thisWeekRows.length,
    last_week_row_count: lastWeekRows.length
  }
}];
